import { basename } from 'node:path';
import { mutateData } from "../../../../lib/utils/object.js";
import { editPropertiesFileCallback } from "../../../base-core/support/properties-file.js";
import { addJavaAnnotation, addJavaImport } from "../../../java/support/add-java-annotation.js";
import { createEnumNeedleCallback } from "../../../java/support/java-enum.js";
import { injectJavaConstructorParam, injectJavaConstructorSetter, injectJavaField } from "../../../java/support/java-file-edit.js";
import { mutateApplicationLoading, mutateApplicationPreparing } from "../../application.js";
import { JavaSimpleApplicationGenerator } from "../../generator.js";
import { getGradleLibsVersionsProperties } from "../gradle/support/dependabot-gradle.js";
import { getPomVersionProperties } from "../maven/support/dependabot-maven.js";
export default class BootstrapGenerator extends JavaSimpleApplicationGenerator {
    async beforeQueue() {
        if (!this.fromBlueprint) {
            await this.composeWithBlueprints();
        }
        await this.dependsOnBootstrap('base-simple-application');
    }
    get loading() {
        return this.asLoadingTaskGroup({
            setupServerconsts({ applicationDefaults }) {
                applicationDefaults(mutateApplicationLoading);
            },
        });
    }
    get [JavaSimpleApplicationGenerator.LOADING]() {
        return this.delegateTasksToBlueprint(() => this.loading);
    }
    get preparing() {
        return this.asPreparingTaskGroup({
            applicationDefaults({ application, applicationDefaults }) {
                applicationDefaults({
                    __override__: false,
                    javaVersion: this.useVersionPlaceholders ? 'JAVA_VERSION' : undefined,
                    projectVersion: '0.0.1-SNAPSHOT',
                    jhipsterDependenciesVersion: () => {
                        if (this.useVersionPlaceholders) {
                            return 'JHIPSTER_DEPENDENCIES_VERSION';
                        }
                        return undefined;
                    },
                    graalvmReachabilityMetadata: () => (this.useVersionPlaceholders ? 'GRAALVM_REACHABILITY_METADATA_VERSION' : undefined),
                }, mutateApplicationPreparing);
                application.prettierExtensions?.push('java');
            },
            log({ application }) {
                if (application.defaultPackaging === 'war') {
                    this.log.info(`Using ${application.defaultPackaging} as default packaging`);
                }
            },
            async loadJavaDependencies({ application }) {
                const pomFile = this.readTemplate(this.fetchFromInstalledJHipster('server/resources/pom.xml'))?.toString();
                const gradleLibsVersions = this.readTemplate(this.fetchFromInstalledJHipster('server/resources/gradle/libs.versions.toml'))?.toString();
                const applicationJavaDependencies = this.prepareDependencies({
                    ...getPomVersionProperties(pomFile),
                    ...getGradleLibsVersionsProperties(gradleLibsVersions),
                }, 'java');
                mutateData(application.javaDependencies, applicationJavaDependencies);
            },
            prepareJavaApplication({ application, source }) {
                source.hasJavaProperty = (property) => application.javaProperties[property] !== undefined;
                source.hasJavaManagedProperty = (property) => application.javaManagedProperties[property] !== undefined;
                source.editJUnitPlatformProperties = properties => this.editFile(`${application.srcTestResources}junit-platform.properties`, { create: true }, editPropertiesFileCallback(properties, { sortFile: true }));
            },
            editJavaFileNeedles({ source }) {
                source.editJavaFile = (file, { staticImports = [], imports = [], annotations = [], constructorParams = [], fields = [], springBeans = [] }, ...editFileCallback) => {
                    const className = basename(file, '.java');
                    return this.editFile(file, ...staticImports.map(classPath => addJavaImport(classPath, { staticImport: true })), ...imports.map(classPath => addJavaImport(classPath)), ...annotations.map(annotation => addJavaAnnotation(annotation)), constructorParams.length > 0 ? injectJavaConstructorParam({ className, param: constructorParams }) : c => c, fields.length > 0 ? injectJavaField({ className, field: fields }) : c => c, ...springBeans.flatMap(({ package: javaPackage, beanClass, beanName }) => [
                        addJavaImport(`${javaPackage}.${beanClass}`),
                        injectJavaField({ className, field: `private final ${beanClass} ${beanName};` }),
                        injectJavaConstructorParam({ className, param: `${beanClass} ${beanName}` }),
                        injectJavaConstructorSetter({ className, setter: `this.${beanName} = ${beanName};` }),
                    ]), ...editFileCallback);
                };
            },
            addItemsToJavaEnumFile({ source }) {
                source.addItemsToJavaEnumFile = (file, { enumName = basename(file, '.java'), enumValues }) => this.editFile(file, createEnumNeedleCallback({ enumName, enumValues }));
            },
        });
    }
    get [JavaSimpleApplicationGenerator.PREPARING]() {
        return this.delegateTasksToBlueprint(() => this.preparing);
    }
}
